function CsvViewer() {
  const [csvText, setCsvText] = React.useState('Name,Age,City,Score\nAlice,30,New York,85\nBob,25,Los Angeles,90\nCharlie,35,Chicago,78\nDiana,28,Miami,92');
  const [delimiter, setDelimiter] = React.useState(',');

  function parseCSV(text, delim) {
    const lines = text.trim().split('\n');
    return lines.map(line => {
      const result = [];
      let current = '';
      let inQuotes = false;
      for (let i = 0; i < line.length; i++) {
        const ch = line[i];
        if (ch === '"' && inQuotes && line[i + 1] === '"') {
          current += '"';
          i++;
        } else if (ch === '"') {
          inQuotes = !inQuotes;
        } else if (ch === delim && !inQuotes) {
          result.push(current);
          current = '';
        } else {
          current += ch;
        }
      }
      result.push(current);
      return result;
    });
  }

  const rows = parseCSV(csvText, delimiter);
  const headers = rows[0] || [];
  const dataRows = rows.slice(1);

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#fff', borderRadius: 12, height: '100%', boxSizing: 'border-box', display: 'flex', flexDirection: 'column' }}>
      <h2 style={{ margin: '0 0 12px 0', fontSize: 18, color: '#1a1a1a' }}>CSV Viewer</h2>
      <div style={{ display: 'flex', gap: 8, marginBottom: 12 }}>
        <input placeholder="Delimiter" value={delimiter} onChange={e => setDelimiter(e.target.value)} maxLength={1} style={{ width: 50, padding: '6px 10px', borderRadius: 6, border: '1px solid #ddd', fontSize: 13, textAlign: 'center' }} />
        <button onClick={() => setCsvText('')} style={{ padding: '6px 14px', borderRadius: 6, border: '1px solid #ddd', background: '#fff', fontSize: 13, cursor: 'pointer' }}>Clear</button>
      </div>
      <textarea
        value={csvText}
        onChange={e => setCsvText(e.target.value)}
        style={{ width: '100%', height: 80, padding: 10, borderRadius: 6, border: '1px solid #ddd', fontSize: 12, fontFamily: 'monospace', resize: 'none', boxSizing: 'border-box', marginBottom: 12 }}
        placeholder="Paste CSV data here..."
      />
      <div style={{ flex: 1, overflow: 'auto', border: '1px solid #e5e7eb', borderRadius: 6 }}>
        <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13 }}>
          <thead>
            <tr>
              {headers.map((h, i) => (
                <th key={i} style={{ padding: '8px 12px', textAlign: 'left', background: '#f3f4f6', borderBottom: '1px solid #e5e7eb', fontWeight: 600, color: '#374151', whiteSpace: 'nowrap' }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {dataRows.map((row, ri) => (
              <tr key={ri} style={{ background: ri % 2 === 0 ? '#fff' : '#f9fafb' }}>
                {row.map((cell, ci) => (
                  <td key={ci} style={{ padding: '8px 12px', borderBottom: '1px solid #e5e7eb', color: '#4b5563', whiteSpace: 'nowrap' }}>{cell}</td>
                ))}
                {row.length < headers.length && Array.from({ length: headers.length - row.length }).map((_, ci) => (
                  <td key={'empty-' + ci} style={{ padding: '8px 12px', borderBottom: '1px solid #e5e7eb' }} />
                ))}
              </tr>
            ))}
          </tbody>
        </table>
        {rows.length <= 1 && <div style={{ textAlign: 'center', color: '#999', fontSize: 13, padding: 20 }}>Enter CSV data to view table.</div>}
      </div>
    </div>
  );
}
render(<CsvViewer/>);
